figma.showUI(__html__,{width:960,height:720});const e=figma,i=typeof e.fileKey=="string"?e.fileKey:"";figma.ui.postMessage({type:"current-file-key",data:{fileKey:i}});figma.ui.onmessage=async t=>{if(t.type==="save-settings"&&figma.root.setPluginData("settings",JSON.stringify(t.data)),t.type==="get-settings"){const a=figma.root.getPluginData("settings");figma.ui.postMessage({type:"settings",data:a})}if(t.type==="save-tasks"&&figma.root.setPluginData("tasks",JSON.stringify(t.data)),t.type==="get-tasks"){const a=figma.root.getPluginData("tasks");figma.ui.postMessage({type:"tasks",data:a})}t.type==="clear-tasks"&&figma.root.setPluginData("tasks","")};
